 41→/// Parsed frontend capabilities from the handshake response.
 42→///
 43→/// During handshake, frontends declare which commands they support and which
 44→/// complex types they can reconstruct. The core uses this to avoid generating
 45→/// complex-typed inputs the frontend can't handle.
 46→#[derive(Debug, Clone, Default)]
 47→pub struct FrontendCapabilities {
 48→    /// Standard commands the frontend supports ("analyze", "execute", etc.).
 49→    pub commands: HashSet<String>,
 50→    /// Complex types the frontend can reconstruct from `__complex_type` JSON.
 51→    pub complex_types: HashSet<ComplexKind>,
 52→}
 53→
 54→impl FrontendCapabilities {
 55→    /// Parse raw capability strings from a handshake response.
 56→    ///
 57→    /// Strings prefixed with `"complex_type:"` are parsed as `ComplexKind` values.
 58→    /// All other strings are treated as command capabilities.
 59→    /// Unknown complex type names are silently ignored.
 60→    pub fn from_raw(capabilities: &[String]) -> Self {
 61→        let mut commands = HashSet::new();
 62→        let mut complex_types = HashSet::new();
 63→        for cap in capabilities {
 64→            if let Some(kind_str) = cap.strip_prefix("complex_type:") {
 65→                // ComplexKind uses serde rename_all = "snake_case", so we
 66→                // deserialize the bare string as a JSON string value.
 67→                if let Ok(kind) = serde_json::from_value::<ComplexKind>(
 68→                    serde_json::Value::String(kind_str.to_string()),
 69→                ) {
 70→                    complex_types.insert(kind);
 71→                }
 72→                // Silently ignore unknown complex type names
 73→            } else {
 74→                commands.insert(cap.clone());
 75→            }
 76→        }
 77→        Self {
 78→            commands,
 79→            complex_types,
 80→        }
 81→    }
 82→
 83→    /// Check whether the frontend declared support for a specific complex type.
 84→    pub fn supports_complex(&self, kind: ComplexKind) -> bool {
 85→        self.complex_types.contains(&kind)
 86→    }
 87→}
