414→/// Result of trying to observe a single worklist entry.
415→enum ObserveOneResult {
416→    /// Entry was executed and produced an observation.
417→    Observed(Box<Observation>),
418→    /// Entry was skipped by triage prediction.
419→    TriageSkipped,
420→    /// Frontend returned an error or unexpected response — entry skipped.
421→    FrontendSkipped,
422→    /// A termination budget was hit before executing.
423→    Terminated(TerminationReason),
424→}
425→
426→/// Execute a single worklist entry and classify the result.
427→///
428→/// Returns an `Observation` with path classification, or a skip/termination
429→/// indicator. The caller is responsible for updating coverage state afterward.
430→#[allow(clippy::too_many_arguments)] // setup_context needed for parity with explorer
431→async fn observe_one(
432→    entry: &WorklistEntry,
433→    frontend: &mut Frontend,
434→    function_name: &str,
435→    config: &ExploreConfig,
436→    covered_paths: &mut HashSet<u64>,
437→    triage_state: &mut TriageState,
438→    budget: &ExploreBudget,
439→    setup_context: &Option<SetupContextStack>,
440→) -> Result<ObserveOneResult, ExploreError> {
441→    // Check termination budgets.
442→    if budget.unique_paths >= config.max_iterations {
443→        return Ok(ObserveOneResult::Terminated(TerminationReason::MaxIterations));
444→    }
445→    if budget.total_executions >= config.max_executions {
446→        return Ok(ObserveOneResult::Terminated(TerminationReason::MaxExecutions));
447→    }
448→    if let Some(timeout) = config.timeout_explore
449→        && budget.explore_start.elapsed() >= timeout
450→    {
451→        return Ok(ObserveOneResult::Terminated(TerminationReason::TimeoutExplore));
452→    }
453→    if config.plateau_threshold > 0 && budget.plateau_counter >= config.plateau_threshold {
454→        return Ok(ObserveOneResult::Terminated(TerminationReason::CoveragePlateau));
455→    }
456→
457→    // Triage: predict whether this input will produce a novel path.
458→    let is_sampled_skip = if entry.source != InputSource::UserProvided {
459→        let verdict = triage_state.triage_candidate(&entry.inputs, covered_paths);
460→        triage_state.record_verdict(&verdict);
461→        if verdict == TriageVerdict::Skip {
462→            if triage_state.should_sample() {
463→                true
464→            } else {
465→                return Ok(ObserveOneResult::TriageSkipped);
466→            }
467→        } else {
468→            false
469→        }
470→    } else {
471→        false
472→    };
473→
474→    // Use entry-level mocks when available, falling back to config.mocks.
475→    let effective_mocks = if entry.mock_values.is_empty() {
476→        &config.mocks
477→    } else {
478→        &entry.mock_values
479→    };
480→
481→    // Execute concretely via the frontend.
482→    let response = frontend
483→        .send(Command::Execute {
484→            function: function_name.to_string(),
485→            inputs: entry.inputs.clone(),
486→            mocks: effective_mocks.clone(),
487→            setup_context: setup_context.clone(),
488→        })
489→        .await?;
490→
491→    let exec_result = match response.result {
492→        ResponseResult::Execute(result) => *result,
493→        ResponseResult::Error { message, .. } => {
494→            log::warn!("frontend error during execute: {message}");
495→            return Ok(ObserveOneResult::FrontendSkipped);
496→        }
497→        _ => return Ok(ObserveOneResult::FrontendSkipped),
498→    };
499→
500→    let path_id = hash_branch_path(&exec_result.branch_path);
501→
502→    // Validate sampled skip prediction before modifying covered_paths.
503→    if is_sampled_skip {
504→        let already_covered = covered_paths.contains(&path_id);
505→        triage_state.record_sample(0, if already_covered { 0 } else { 1 });
506→    }
507→
508→    let is_new_path = covered_paths.insert(path_id);
509→    if is_new_path {
510→        triage_state.update(&exec_result.branch_path);
511→    }
512→
513→    Ok(ObserveOneResult::Observed(Box::new(Observation {
514→        inputs: entry.inputs.clone(),
515→        result: exec_result,
516→        source: entry.source,
517→        path_id,
518→        is_new_path,
519→        is_sampled_skip,
520→        mock_values: entry.mock_values.clone(),
521→    })))
522→}
523→
524→/// Budget counters checked by `observe_one` to enforce termination limits.
525→struct ExploreBudget {
526→    unique_paths: usize,
527→    total_executions: usize,
528→    plateau_counter: usize,
529→    explore_start: Instant,
530→}
531→
532→/// Solve/Generate phase: process new-path observations and produce candidate inputs.
533→///
534→/// For each new-path observation:
535→/// - Extract symbolic constraints and negate each with Z3
536→/// - Try boundary search for Unknown constraints (interpolate between witnesses)
537→/// - Fall back to blind fuzzing for Unknown constraints without witnesses
538→/// - Drill stalled frontiers with targeted mutations
539→#[allow(clippy::too_many_arguments)] // boundary search + fitness scoring need broad context
540→fn solve_and_generate(
541→    observations: &[Observation],
542→    frontier_set: &mut FrontierSet,
543→    param_infos: &[ParamInfo],
544→    param_names: &[String],
545→    raw_results: &[(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)],
546→    seen_branch_sides: &std::collections::HashSet<(u32, bool)>,
547→    config: &ExploreConfig,
548→    rng: &mut StdRng,
549→    target_branches: &HashSet<u32>,

550→    fitness_context: &mut FitnessContext,
551→    fitness_weights: &FitnessWeights,
552→    mock_params: &[MockParam],
553→) -> SolveOutput {
554→    let mut output = SolveOutput::default();
555→
556→    for obs in observations.iter().filter(|o| o.is_new_path) {
557→        // Extract symbolic constraints from the branch path.
558→        let sym_constraints = extract_sym_constraints(&obs.result);
559→
560→        // Collect solvable constraints with their original branch_path indices.
561→        let solvable_with_idx: Vec<(usize, SymExpr)> = sym_constraints
562→            .iter()
563→            .enumerate()
564→            .filter_map(|(i, c)| c.as_ref().map(|e| (i, e.clone())))
565→            .collect();
566→        let solvable: Vec<SymExpr> = solvable_with_idx.iter().map(|(_, e)| e.clone()).collect();
567→
568→        // Try to negate each branch constraint with Z3.
569→        if !solvable.is_empty() {
570→            for (solve_idx, &(branch_idx, _)) in solvable_with_idx.iter().enumerate() {
571→                match solver::solve_for_new_path(&solvable, solve_idx, config.solver_timeout_ms, param_infos) {
572→                    Ok(SolveResult::Sat(values)) => {
573→                        let new_inputs =
574→                            overlay_solved_values(&obs.inputs, &values, param_names);
575→                        output.candidates.push(WorklistEntry {
576→                            inputs: new_inputs,
577→                            source: InputSource::Z3Solved,
578→                            fitness: None,
579→                            mock_values: obs.mock_values.clone(),
580→                        });
581→                        output.z3_count += 1;
582→                    }
583→                    Ok(SolveResult::Unsat) => {
584→                        if let Some(bd) = obs.result.branch_path.get(branch_idx) {
585→                            frontier_set.increment_stall(bd.branch_id);
586→                        }
587→                    }
588→                    Err(_) => {
589→                        if let Some(bd) = obs.result.branch_path.get(branch_idx) {
590→                            frontier_set.increment_stall(bd.branch_id);
591→                        }
592→                    }
593→                }
594→            }
595→        }
596→
597→        // For Unknown constraints, try boundary search first (interpolate between
598→        // true/false witnesses), then fall back to blind fuzzing.
599→        let mut boundary_attempted = false;
600→        let mut boundary_branches = 0usize;
601→        for (i, constraint_opt) in sym_constraints.iter().enumerate() {
602→            if constraint_opt.is_none() && i < obs.result.branch_path.len() {
603→                let bd = &obs.result.branch_path[i];
604→                let opposite_seen =
605→                    seen_branch_sides.contains(&(bd.branch_id, !bd.taken));
606→
607→                if opposite_seen
608→                    && let Some((tw, fw)) =
609→                        boundary_search::find_witness_pair(raw_results, bd.branch_id)
610→                {
611→                    let candidates = boundary_search::interpolate_inputs(
612→                        &tw,
613→                        &fw,
614→                        param_infos,
615→                        boundary_search::MAX_BOUNDARY_STEPS,
616→                    );
617→                    for interp in candidates {
618→                        output.candidates.push(WorklistEntry {
619→                            inputs: interp,
620→                            source: InputSource::BoundarySearch,
621→                            fitness: None,
622→                            mock_values: obs.mock_values.clone(),
623→                        });
624→                        output.boundary_count += 1;
625→                    }
626→                    boundary_attempted = true;
627→                    boundary_branches += 1;
628→                    if boundary_branches
629→                        >= boundary_search::MAX_BOUNDARY_BRANCHES_PER_ROUND
630→                    {
631→                        break;
632→                    }
633→                }
634→            }
635→        }
636→
637→        // Fall back to type-aware mutation if boundary search wasn't applicable.
638→        //
639→        // Uses input_gen::mutate_inputs (type-aware, respects param types) for
640→        // several rounds, plus the legacy fuzz_inputs as a cheap supplement.
641→        if !boundary_attempted {
642→            for (i, constraint_opt) in sym_constraints.iter().enumerate() {
643→                if constraint_opt.is_none() && i < obs.result.branch_path.len() {
644→                    // Type-aware mutations (3 rounds at full mutation rate).
645→                    for _ in 0..MUTATE_ROUNDS_PER_UNKNOWN {
646→                        let mutated = input_gen::mutate_inputs(
647→                            &obs.inputs,
648→                            param_infos,
649→                            MUTATE_RATE_UNKNOWN,
650→                            &[],
651→                            rng,
652→                        );
653→                        let mutated_mocks = if !mock_params.is_empty() {
654→                            input_gen::mutate_mock_values(
655→                                &obs.mock_values,
656→                                mock_params,
657→                                MUTATE_RATE_UNKNOWN,
658→                                &[],
659→                                rng,
660→                            )
661→                        } else {
662→                            obs.mock_values.clone()
663→                        };
664→                        output.candidates.push(WorklistEntry {
665→                            inputs: mutated,
666→                            source: InputSource::Fuzzed,
667→                            fitness: None,
668→                            mock_values: mutated_mocks,
669→                        });
670→                        output.fuzz_count += 1;
671→                    }
672→                    // Legacy deterministic fuzz as supplement.
673→                    for fuzzed in fuzz_inputs(&obs.inputs) {
674→                        output.candidates.push(WorklistEntry {
675→                            inputs: fuzzed,
676→                            source: InputSource::Fuzzed,
677→                            fitness: None,
678→                            mock_values: obs.mock_values.clone(),
679→                        });
680→                        output.fuzz_count += 1;
681→                    }
682→                    // Only fuzz once per observation (avoid exponential blowup).
683→                    break;
684→                }
685→            }
686→        }
687→    }
688→
689→    // Parameter drilling: for stalled frontiers, generate targeted mutations.
690→    {
691→        let mut stalled: Vec<Frontier> = frontier_set
692→            .iter()
693→            .filter(|f| {
694→                f.stall_count >= drilling::DRILL_STALL_THRESHOLD
695→                    && f.stall_count < crate::frontier::DEFAULT_MAX_STALL
696→            })
697→            .cloned()
698→            .collect();
699→        stalled.sort_by(|a, b| a.depth.cmp(&b.depth).then(a.stall_count.cmp(&b.stall_count)));

700→        stalled.truncate(drilling::MAX_FRONTIERS_PER_ROUND);
701→
702→        for frontier in &stalled {
703→            let count =
704→                drilling::DRILL_MUTATIONS_PER_PARAM * frontier.blocking_params.len().max(1);
705→            let drilled = drilling::generate_drilled_inputs(
706→                &frontier.best_prefix,
707→                &frontier.blocking_params,
708→                param_infos,
709→                count,
710→                rng,
711→            );
712→            for inputs in drilled {
713→                output.candidates.push(WorklistEntry {
714→                    inputs,
715→                    source: InputSource::Drilled,
716→                    fitness: None,
717→                    mock_values: vec![],
718→                });
719→                output.drill_count += 1;
720→            }
721→            frontier_set.increment_stall(frontier.branch_id);
722→        }
723→    }
724→
725→    // Score each candidate using genetic fitness. The parent observation's
726→    // branch path gives us approximate fitness context: candidates derived
727→    // from high-fitness executions should be explored first.
728→    if !target_branches.is_empty() {
729→        for candidate in &mut output.candidates {
730→            // Create a synthetic ExecuteResult from the parent observation's
731→            // branch path to estimate fitness. This gives candidates a
732→            // relative ranking even before execution.
733→            if let Some(parent_obs) = observations.iter().find(|o| o.is_new_path) {
734→                let breakdown = crate::genetic_fitness::score(
735→                    &parent_obs.result,
736→                    target_branches,
737→                    fitness_context,
738→                    fitness_weights,
739→                );
740→                candidate.fitness = Some(breakdown.total);
741→            }
742→        }
743→    }
744→
745→    output
746→}
