476→/// Send a Setup command to the frontend and return a `SetupContextStack`
477→/// containing the returned context at the given level.
478→pub(crate) async fn send_setup(
479→    frontend: &mut Frontend,
480→    setup_file: &str,
481→    scope: &str,
482→    level: SetupLevel,
483→    project_root: Option<String>,
484→) -> Result<Option<SetupContextStack>, ExploreError> {
485→    let response = frontend
486→        .send(ProtoCommand::Setup {
487→            file: setup_file.to_string(),
488→            scope: scope.to_string(),
489→            level,
490→            project_root,
491→            parent_context: None,
492→        })
493→        .await?;
494→    match response.result {
495→        ResponseResult::Setup { setup_context } => Ok(Some(SetupContextStack {
496→            contexts: vec![SetupContextEntry {
497→                level,
498→                context: setup_context,
499→            }],
500→        })),
501→        ResponseResult::Error { message, .. } => {
502→            log::warn!("setup error for {scope}: {message}");
503→            Ok(None)
504→        }
505→        other => Err(ExploreError::UnexpectedResponse(format!(
506→            "expected Setup response, got {other:?}"
507→        ))),
508→    }
509→}
