531→/// Explore a single function by generating random inputs and executing them.
532→///
533→/// When `setup_mgr` is provided, setup lifecycle is tracked through the
534→/// `SetupManager` (context caching, failure tracking, skip decisions).
535→/// When `None`, uses the legacy direct-send approach.
536→pub async fn explore_function(
537→    frontend: &mut Frontend,
538→    analysis: &FunctionAnalysis,
539→    config: &ExploreConfig,
540→    mut setup_mgr: Option<&mut SetupManager>,
541→) -> Result<ObservationOutput, ExploreError> {
542→    let instrument_response = frontend
543→        .send(ProtoCommand::Instrument {
544→            file: config.file.clone(),
545→            function: analysis.name.clone(),
546→            mocks: config.mocks.clone(),
547→            project_root: config.project_root.clone(),
548→        })
549→        .await?;

550→
551→    let instrumentable_line_count = match instrument_response.result {
552→        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
553→            if !instrumented {
554→                return Err(ExploreError::UnexpectedResponse(
555→                    "instrumentation returned instrumented=false".to_string(),
556→                ));
557→            }
558→            instrumentable_line_count
559→        }
560→        ResponseResult::Error { code, message, .. } => {
561→            return Err(ExploreError::UnexpectedResponse(format!(
562→                "instrument error ({code:?}): {message}"
563→            )));
564→        }
565→        other => {
566→            return Err(ExploreError::UnexpectedResponse(format!(
567→                "expected Instrument response, got {other:?}"
568→            )));
569→        }
570→    };
571→
572→    let mut rng = match config.seed {
573→        Some(seed) => StdRng::seed_from_u64(seed),
574→        None => StdRng::from_os_rng(),
575→    };
576→
577→    // --- Setup lifecycle ---
578→    let has_setup =
579→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
580→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
581→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
582→
583→    let mut setup_context: Option<SetupContextStack> = None;
584→
585→    // When a SetupManager is provided, check should_skip and cache contexts.
586→    let skip_setup = setup_mgr.as_ref().is_some_and(|m| m.should_skip(config.setup_level));
587→
588→    if per_function_setup && !skip_setup
589→        && let Some(ref setup_file) = config.setup_file
590→    {
591→        match send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await? {
592→            Some(ctx) => {
593→                if let Some(ref mut mgr) = setup_mgr
594→                    && let Some(entry) = ctx.contexts.first()
595→                {
596→                    let _ = mgr.setup(config.setup_level, &analysis.name, entry.context.clone());
597→                }
598→                setup_context = Some(ctx);
599→            }
600→            None => {
601→                if let Some(ref mut mgr) = setup_mgr {
602→                    let _ = mgr.record_failure(
603→                        config.setup_level,
604→                        format!("setup returned no context for {}", analysis.name),
605→                    );
606→                }
607→            }
608→        }
609→    }
610→
611→    // --- Generator prefetch ---
612→    let has_generators = config
613→        .value_sources
614→        .iter()
615→        .any(|s| matches!(s, ValueSource::CustomGenerator { .. }));
616→    let use_generators = has_generators && frontend_supports(&config.capabilities, "generate");
617→
618→    let mut prefetched = if use_generators {
619→        prefetch_custom_values(&config.value_sources, frontend, config.max_iterations as usize)
620→            .await
621→            .unwrap_or_else(|e| {
622→                log::debug!("prefetch failed, falling back to built-in: {e}");
623→                PrefetchedValues::new()
624→            })
625→    } else {
626→        PrefetchedValues::new()
627→    };
628→
629→    let mut seen_paths: HashSet<u64> = HashSet::new();
630→    let mut all_lines: HashSet<u32> = HashSet::new();
631→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
632→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
633→    let mut iterations: u32 = 0;
634→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
635→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
636→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
637→
638→    // --- Float probe phase ---
639→    // Probes consume from the iteration budget, contributing to seen_paths and raw_results.
640→    let float_indices = crate::float_probe::float_param_indices(&analysis.params);
641→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
642→    let probe_budget = float_indices.len() * crate::float_probe::PROBE_COUNT * 2;
643→    if !float_indices.is_empty() && probe_budget < config.max_iterations as usize {
644→        for &idx in &float_indices {
645→            let pairs = crate::float_probe::generate_probe_pairs(
646→                &analysis.params,
647→                idx,
648→                crate::float_probe::PROBE_COUNT,
649→                &mut rng,
650→            );
651→            let mut agreements = 0usize;
652→            let mut total_probes = 0usize;
653→            let mut divergent_values = Vec::new();
654→
655→            for (float_inputs, floor_inputs) in pairs {
656→                let float_resp = frontend
657→                    .send(ProtoCommand::Execute {
658→                        function: analysis.name.clone(),
659→                        inputs: float_inputs.clone(),
660→                        mocks: config.mocks.clone(),
661→                        setup_context: setup_context.clone(),
662→                    })
663→                    .await?;
664→
665→                let floor_resp = frontend
666→                    .send(ProtoCommand::Execute {
667→                        function: analysis.name.clone(),
668→                        inputs: floor_inputs,
669→                        mocks: config.mocks.clone(),
670→                        setup_context: setup_context.clone(),
671→                    })
672→                    .await?;
673→
674→                if let (
675→                    ResponseResult::Execute(float_result),
676→                    ResponseResult::Execute(floor_result),
677→                ) = (&float_resp.result, &floor_resp.result) {
678→                    total_probes += 1;
679→
680→                    let fhash = path_hash(float_result, &config.loop_buckets);
681→                    let flhash = path_hash(floor_result, &config.loop_buckets);
682→                    seen_paths.insert(fhash);
683→                    seen_paths.insert(flhash);
684→                    for &line in &float_result.lines_executed {
685→                        all_lines.insert(line);
686→                    }
687→                    for &line in &floor_result.lines_executed {
688→                        all_lines.insert(line);
689→                    }
690→
691→                    if crate::float_probe::executions_agree(float_result, floor_result) {
692→                        agreements += 1;
693→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
694→                        divergent_values.push(v);
695→                    }
696→
697→                    raw_results.push((float_inputs.clone(), config.mocks.clone(), (**float_result).clone()));
698→                }
699→            }
700→
701→            let classification = crate::float_probe::classify(
702→                agreements,
703→                total_probes,
704→                crate::float_probe::AGREEMENT_THRESHOLD,
705→            );
706→            float_probe_results.push(crate::float_probe::FloatProbeResult {
707→                param_index: idx,
708→                param_name: analysis.params[idx].name.clone(),
709→                classification,
710→                agreements,
711→                total_probes,
712→                divergent_values,
713→            });
714→        }
715→    }
716→
717→    let float_bias = crate::float_probe::build_bias_map(&float_probe_results);
718→    let has_integer_treating = float_bias
719→        .values()
720→        .any(|c| *c == crate::float_probe::FloatClassification::IntegerTreating);
721→
722→    // --- User-provided candidate inputs (highest priority, no budget cap) ---
723→    let mut user_iter = config.user_seeds.iter().cloned().peekable();
724→
725→    // --- Literal-derived seed inputs ---
726→    // Execute extracted literals first to cover magic-value branches before random exploration.
727→    let literal_candidates = literals_to_candidate_inputs(&analysis.params, &analysis.literals);
728→    let literal_budget = literal_candidates
729→        .len()
730→        .min(config.max_iterations as usize / 2);
731→    let mut literal_iter = literal_candidates.into_iter().take(literal_budget).peekable();
732→
733→    // --- Candidate inputs (from --inputs or .shatter/ config) ---
734→    // Priority above pool seeds, below literal seeds.
735→    let candidate_budget = config
736→        .candidate_inputs
737→        .len()
738→        .min(config.max_iterations as usize / 3);
739→    let mut candidate_iter = config.candidate_inputs.iter().take(candidate_budget).cloned().peekable();
740→
741→    // --- Pool-derived seed inputs ---
742→    // Cross-function interesting values, injected after literals but before random generation.
743→    let pool_budget = config
744→        .pool_seeds
745→        .len()
746→        .min(config.max_iterations as usize / 4);
747→    let mut pool_iter = config.pool_seeds.iter().take(pool_budget).cloned().peekable();
748→
749→    let explore_start = Instant::now();

750→
751→    for _ in 0..config.max_iterations {
752→        if let Some(timeout) = config.timeout_explore
753→            && explore_start.elapsed() >= timeout
754→        {
755→            break;
756→        }
757→
758→        iterations += 1;
759→
760→        // --- Per-execution setup ---
761→        if per_execution_setup && !skip_setup
762→            && let Some(ref setup_file) = config.setup_file
763→        {
764→            match send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await? {
765→                Some(ctx) => {
766→                    if let Some(ref mut mgr) = setup_mgr
767→                        && let Some(entry) = ctx.contexts.first()
768→                    {
769→                        let _ = mgr.setup(config.setup_level, &analysis.name, entry.context.clone());
770→                    }
771→                    setup_context = Some(ctx);
772→                }
773→                None => {
774→                    if let Some(ref mut mgr) = setup_mgr {
775→                        let _ = mgr.record_failure(
776→                            config.setup_level,
777→                            format!("per-execution setup returned no context for {}", analysis.name),
778→                        );
779→                    }
780→                }
781→            }
782→        }
783→
784→        // --- Input generation ---
785→        // Priority: user seeds → literals → candidate inputs → pool seeds → custom generators → random.
786→        let inputs = if let Some(user_inputs) = user_iter.next() {
787→            user_inputs
788→        } else if let Some(lit_inputs) = literal_iter.next() {
789→            lit_inputs
790→        } else if let Some(cand_inputs) = candidate_iter.next() {
791→            cand_inputs
792→        } else if let Some(pool_inputs) = pool_iter.next() {
793→            pool_inputs
794→        } else if use_generators {
795→            generate_inputs_with_custom(
796→                &analysis.params,
797→                &config.value_sources,
798→                &mut prefetched,
799→                &mut rng,
800→                Some(&config.capabilities),
801→            )
802→        } else if has_integer_treating {
803→            crate::input_gen::generate_random_inputs_with_float_bias(
804→                &analysis.params,
805→                &float_bias,
806→                &mut rng,
807→                None,
808→            )
809→        } else {
810→            generate_random_inputs(&analysis.params, &mut rng, None)
811→        };
812→
813→        // --- Mock generation ---
814→        // When mock_params is non-empty, generate fresh mock values each iteration
815→        // to vary dependency behavior across exploration runs.
816→        let iteration_mocks = if !config.mock_params.is_empty() {
817→            generate_mock_values(&config.mock_params, &mut rng, Some(&config.capabilities))
818→        } else {
819→            config.mocks.clone()
820→        };
821→
822→        let response = frontend
823→            .send(ProtoCommand::Execute {
824→                function: analysis.name.clone(),
825→                inputs: inputs.clone(),
826→                mocks: iteration_mocks.clone(),
827→                setup_context: setup_context.clone(),
828→            })
829→            .await?;
830→
831→        let exec_result = match response.result {
832→            ResponseResult::Execute(result) => *result,
833→            ResponseResult::Error { code, message, .. } => {
834→                return Err(ExploreError::UnexpectedResponse(format!(
835→                    "execute error ({code:?}): {message}"
836→                )));
837→            }
838→            other => {
839→                return Err(ExploreError::UnexpectedResponse(format!("{other:?}")));
840→            }
841→        };
842→
843→        // --- Per-execution teardown ---
844→        if per_execution_setup && !skip_setup && frontend_supports(&config.capabilities, "teardown") {
845→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
846→            if let Some(ref mut mgr) = setup_mgr {
847→                mgr.teardown(config.setup_level, &analysis.name);
848→            }
849→        }
850→
851→        for &line in &exec_result.lines_executed {
852→            all_lines.insert(line);
853→        }
854→
855→        let hash = path_hash(&exec_result, &config.loop_buckets);
856→        *path_counts.entry(hash).or_insert(0) += 1;
857→        let is_new = seen_paths.insert(hash);
858→
859→        // Track per-branch discovery attribution.
860→        for decision in &exec_result.branch_path {
861→            if seen_branch_ids.insert(decision.branch_id) {
862→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
863→            }
864→        }
865→
866→        if is_new {
867→            let error_intent = classify_error_intent(&exec_result);
868→            new_path_executions.push(ExecutionSummary {
869→                inputs: inputs.clone(),
870→                return_value: exec_result.return_value.clone(),
871→                thrown_error: exec_result
872→                    .thrown_error
873→                    .as_ref()
874→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
875→                lines_executed: exec_result.lines_executed.clone(),
876→                is_new_path: true,
877→                error_intent,
878→            });
879→        }
880→
881→        raw_results.push((inputs, iteration_mocks, exec_result));
882→    }
883→
884→    // --- Per-function teardown ---
885→    if per_function_setup && !skip_setup && frontend_supports(&config.capabilities, "teardown") {
886→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
887→        if let Some(ref mut mgr) = setup_mgr {
888→            mgr.teardown(config.setup_level, &analysis.name);
889→        }
890→    }
891→
892→    let total_lines = instrumentable_line_count
893→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
894→
895→    Ok(ObservationOutput {
896→        function_name: analysis.name.clone(),
897→        iterations,
898→        unique_paths: seen_paths.len(),
899→        lines_covered: all_lines.len(),
900→        total_lines,
901→        new_path_executions,
902→        raw_results,
903→        discoveries,
904→        nondeterministic_fields: vec![],
905→        float_probe_results,
906→    })
907→}
