100→        self.frontiers.len()
101→    }
102→
103→    pub fn is_empty(&self) -> bool {
104→        self.frontiers.is_empty()
105→    }
106→
107→    /// Iterate over all frontiers in arbitrary order.
108→    pub fn iter(&self) -> impl Iterator<Item = &Frontier> {
109→        self.frontiers.iter()
110→    }
111→
112→    /// Index of the highest-priority frontier.
113→    /// Caller must ensure `self.frontiers` is non-empty.
114→    fn best_index(&self) -> usize {
115→        self.frontiers
116→            .iter()
117→            .enumerate()
118→            .min_by(|(_, a), (_, b)| frontier_priority(a, b))
119→            .map(|(i, _)| i)
120→            .expect("best_index called on non-empty FrontierSet")
121→    }
122→}
123→
124→/// Compare two frontiers for priority ordering.
125→/// Lower depth wins; ties broken by lower stall count.
126→fn frontier_priority(a: &Frontier, b: &Frontier) -> std::cmp::Ordering {
127→    a.depth.cmp(&b.depth).then(a.stall_count.cmp(&b.stall_count))
128→}
